import json
import os
from pathlib import Path
from collections import defaultdict

backtest_dir = Path("reports/backtest")
files = list(backtest_dir.glob("*.json"))

# Sample various strategies to analyze patterns
strategies_to_analyze = [
    "ma", "adx", "ichimoku", "roc", "rsi_divergence", 
    "parabolic_sar", "mean_reversion", "bb_squeeze", "atr", "elder_ray"
]

results = {}

for file in files:
    filename = file.name
    for strategy in strategies_to_analyze:
        if strategy in filename:
            try:
                with open(file, 'r') as f:
                    data = json.load(f)
                    trades = data.get("trades", [])

                    buys = sum(1 for t in trades if 'BUY' in t['order_type'] and 'CLOSE' not in t['order_type'])
                    sells = sum(1 for t in trades if 'SELL' in t['order_type'] and 'CLOSE' not in t['order_type'])

                    if strategy not in results:
                        results[strategy] = {"buys": 0, "sells": 0, "tests": 0}

                    results[strategy]["buys"] += buys
                    results[strategy]["sells"] += sells
                    results[strategy]["tests"] += 1
            except:
                pass

print("BIDIRECTIONAL STRATEGIES - ACTUAL BACKTEST BIAS")
print("=" * 70)

for strategy in sorted(results.keys()):
    data = results[strategy]
    total_opens = data["buys"] + data["sells"]
    if total_opens > 0:
        buy_pct = (data["buys"] / total_opens) * 100
        sell_pct = (data["sells"] / total_opens) * 100

        if buy_pct > 60:
            bias = "LONG_BIASED"
        elif sell_pct > 60:
            bias = "SHORT_BIASED"
        else:
            bias = "BALANCED"

        print(f"{strategy:20} | BUY: {data['buys']:4} ({buy_pct:5.1f}%) | SELL: {data['sells']:4} ({sell_pct:5.1f}%) | {bias}")

EOF
